import{c as t,Q as o,j as a,m as s}from"./chunks/framework.BPKcPtvA.js";const n="/demo-mode.png",h=JSON.parse('{"title":"Processing Modes","description":"","frontmatter":{},"headers":[],"relativePath":"guide/modes.md","filePath":"guide/modes.md"}'),i={name:"guide/modes.md"};function d(r,e,l,c,p,u){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="processing-modes" tabindex="-1">Processing Modes <a class="header-anchor" href="#processing-modes" aria-label="Permalink to &quot;Processing Modes&quot;">​</a></h1><p>The status bar shows your current processing mode. Click it to cycle through, or use <code>Cmd+Shift+P</code> → <strong>&quot;Select Processing Mode&quot;</strong> for a full menu.</p><h2 id="mode-selector" tabindex="-1">Mode Selector <a class="header-anchor" href="#mode-selector" aria-label="Permalink to &quot;Mode Selector&quot;">​</a></h2><p>The mode selector sits in the status bar (bottom right), next to the microphone icon:</p><p><img src="'+n+`" alt="Mode selector in status bar"></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🎤 Default    🪄 Magic</span></span></code></pre></div><p>Click the mode label to cycle through:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$(symbol-color) Auto → $(markdown) Markdown → $(code) Code →</span></span>
<span class="line"><span>$(terminal) Terminal → $(git-commit) Commit → $(wand) Magic</span></span></code></pre></div><h2 id="auto-symbol-color" tabindex="-1">Auto <code>$(symbol-color)</code> <a class="header-anchor" href="#auto-symbol-color" aria-label="Permalink to &quot;Auto \`$(symbol-color)\`&quot;">​</a></h2><div style="background:#1e1e1e;padding:12px;border-radius:6px;margin:8px 0;"><p><strong>Best for:</strong> General dictation. Automatically detects the right mode from your active file type.</p><ul><li><code>.md</code> files → Markdown mode</li><li><code>.ts</code>, <code>.js</code>, <code>.py</code> etc. → Code Comment mode</li><li>Terminal focused → Terminal mode</li></ul><p><strong>Routing:</strong> Short text (&lt;100 chars) goes to the free local rules engine. Longer or complex dictation routes to the cheapest capable hosted model (DeepSeek by default).</p></div><h2 id="markdown-markdown" tabindex="-1">Markdown <code>$(markdown)</code> <a class="header-anchor" href="#markdown-markdown" aria-label="Permalink to &quot;Markdown \`$(markdown)\`&quot;">​</a></h2><div style="background:#1e1e1e;padding:12px;border-radius:6px;margin:8px 0;"><p><strong>Best for:</strong> Documentation, READMEs, notes.</p><p><strong>What it does:</strong></p><ul><li>Converts spoken headings: <em>&quot;major header skills transfer&quot;</em> → <code># skills transfer</code></li><li>Converts numbered instructions: <em>&quot;instruction number one is install&quot;</em> → <code>1. install</code></li><li>Converts bullet points: <em>&quot;bullet point configure database&quot;</em> → <code>- configure database</code></li><li>Formats code punctuation: <em>&quot;comma&quot;</em> → <code>,</code>, <em>&quot;semicolon&quot;</em> → <code>;</code></li></ul><p><strong>Example:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Input:  &quot;major header setup instruction number one is install deps instruction number two is run tests&quot;</span></span>
<span class="line"><span>Output: # setup</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        1. install deps.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        2. run tests.</span></span></code></pre></div></div><h2 id="code-comment-code" tabindex="-1">Code Comment <code>$(code)</code> <a class="header-anchor" href="#code-comment-code" aria-label="Permalink to &quot;Code Comment \`$(code)\`&quot;">​</a></h2><div style="background:#1e1e1e;padding:12px;border-radius:6px;margin:8px 0;"><p><strong>Best for:</strong> Dictating code comments, JSDoc, Python docstrings.</p><p><strong>What it does:</strong></p><ul><li>Converts spoken punctuation: <em>&quot;comma&quot;</em> → <code>,</code>, <em>&quot;equals&quot;</em> → <code>=</code>, <em>&quot;plus&quot;</em> → <code>+</code></li><li>Preserves code symbols: <em>&quot;const response equals await fetch&quot;</em> stays verbatim</li><li>Adds a period at the end</li></ul><p><strong>Example:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Input:  &quot;this function handles retry logic comma with exponential backoff&quot;</span></span>
<span class="line"><span>Output: This function handles retry logic, with exponential backoff.</span></span></code></pre></div></div><h2 id="terminal-terminal" tabindex="-1">Terminal <code>$(terminal)</code> <a class="header-anchor" href="#terminal-terminal" aria-label="Permalink to &quot;Terminal \`$(terminal)\`&quot;">​</a></h2><div style="background:#1e1e1e;padding:12px;border-radius:6px;margin:8px 0;"><p><strong>Best for:</strong> Dictating CLI commands.</p><p><strong>What it does:</strong></p><ul><li>Converts spoken flags: <em>&quot;dash dash verbose&quot;</em> → <code>--verbose</code></li><li>Converts single-letter flags: <em>&quot;dash a&quot;</em> → <code>-a</code></li><li>Removes trailing period (commands shouldn&#39;t end with <code>.</code>)</li></ul><p><strong>Example:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Input:  &quot;git commit dash m add user auth&quot;</span></span>
<span class="line"><span>Output: git commit -m add user auth</span></span></code></pre></div></div><h2 id="commit-message-git-commit" tabindex="-1">Commit Message <code>$(git-commit)</code> <a class="header-anchor" href="#commit-message-git-commit" aria-label="Permalink to &quot;Commit Message \`$(git-commit)\`&quot;">​</a></h2><div style="background:#1e1e1e;padding:12px;border-radius:6px;margin:8px 0;"><p><strong>Best for:</strong> Dictating git commit messages in the SCM input box.</p><p><strong>What it does:</strong></p><ul><li>Strips filler phrases: <em>&quot;this is a feature for&quot;</em> → <code>feat:</code></li><li>Uses conventional commit format: <code>feat:</code>, <code>fix:</code>, <code>chore:</code>, <code>docs:</code></li><li>Caps at 72 characters</li><li>Removes trailing language: <em>&quot;the feature is most requested for...&quot;</em></li></ul><p><strong>Example:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Input:  &quot;This is a feature for user input optimization it is able to accept clicks and tags&quot;</span></span>
<span class="line"><span>Output: feat: user input optimization accept clicks</span></span></code></pre></div></div><h2 id="prompt-magic-wand" tabindex="-1">Prompt Magic <code>$(wand)</code> <a class="header-anchor" href="#prompt-magic-wand" aria-label="Permalink to &quot;Prompt Magic \`$(wand)\`&quot;">​</a></h2><div style="background:#1e1e1e;padding:12px;border-radius:6px;margin:8px 0;"><p><strong>Best for:</strong> Full AI enhancement — ideas, documentation, explanations, creative content.</p><p><strong>What it does:</strong></p><ul><li>✅ Removes filler words (<em>um, uh, like, you know, basically</em>)</li><li>✅ Upgrades informal vocabulary: <em>&quot;do the stuff&quot;</em> → <em>&quot;perform the operation&quot;</em></li><li>✅ Converts casual language: <em>&quot;wanna&quot;</em> → <em>&quot;want to&quot;</em>, <em>&quot;gonna&quot;</em> → <em>&quot;going to&quot;</em></li><li>✅ Removes repetitive phrasing: <em>&quot;it should also do inserts as well&quot;</em> → <em>&quot;, do inserts&quot;</em></li><li>✅ Infers structure: headings, numbered lists, paragraphs</li><li>✅ Routes to <strong>hosted language models</strong> for true AI enhancement</li></ul><p><strong>This mode requires a hosted model. It always routes to DeepSeek or OpenAI — never the free rules engine.</strong></p><p><strong>Example:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Input:  &quot;um so like we need to create a thing that connects to the API and you</span></span>
<span class="line"><span>         know makes it amazing and handles all the data stuff&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Output: We need to develop a solution that integrates with the API, ensuring</span></span>
<span class="line"><span>        exceptional performance and comprehensive data management.</span></span></code></pre></div><p><strong>Required:</strong> Configure <code>DEEPSEEK_API_KEY</code> or <code>OPENAI_API_KEY</code> in your <code>.env</code> file.</p></div><h2 id="how-routing-chooses-models" tabindex="-1">How Routing Chooses Models <a class="header-anchor" href="#how-routing-chooses-models" aria-label="Permalink to &quot;How Routing Chooses Models&quot;">​</a></h2><p>The gateway uses <strong>cost-quality scoring</strong> to pick the best model:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Model</th><th>Cost/1K tokens</th><th>Best for</th></tr></thead><tbody><tr><td>Auto (short)</td><td>Rules Engine</td><td>$0</td><td>Simple formatting</td></tr><tr><td>Auto (complex)</td><td>DeepSeek Flash</td><td>$0.00014</td><td>Cleanup, summarization</td></tr><tr><td>Markdown/Code</td><td>DeepSeek Flash</td><td>$0.00014</td><td>Formatting, structure</td></tr><tr><td>Prompt Magic</td><td>DeepSeek Flash</td><td>$0.00014</td><td>Enhancement, generation</td></tr><tr><td>(Pro plan)</td><td>OpenAI GPT-4</td><td>$0.01</td><td>Complex reasoning</td></tr></tbody></table><p>The router evaluates each model&#39;s <strong>capabilities</strong> (<code>bestFor</code> tags), <strong>cost</strong>, and <strong>latency</strong> — then picks the cheapest model that covers the required capabilities for your mode.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/guide/gateway.html">Gateway Setup</a> — prerequisites and startup</li><li><a href="/guide/configuration.html">Configuration</a> — all settings</li></ul>`,26)])])}const g=t(i,[["render",d]]);export{h as __pageData,g as default};
